// Lógica: verificar si hoy es día de obligación fiscal
// ISR/IVA: día 17 de cada mes
// DIOT: día 17 del mes siguiente
// Contabilidad electrónica: día 3 del mes siguiente
// Declaración anual: 31 marzo (PF) / 31 marzo (PM)
const today = new Date();
const day = today.getDate();
const month = today.getMonth() + 1;
const obligations = [];

if (day === 17) {
  obligations.push({ tipo: 'ISR', descripcion: 'Pago provisional ISR', urgente: true });
  obligations.push({ tipo: 'IVA', descripcion: 'Pago mensual IVA', urgente: true });
  obligations.push({ tipo: 'DIOT', descripcion: 'Declaración Informativa de Operaciones con Terceros', urgente: true });
}
if (day === 3) {
  obligations.push({ tipo: 'CONTABILIDAD', descripcion: 'Envío contabilidad electrónica al SAT', urgente: false });
}
if (month === 3 && day === 31) {
  obligations.push({ tipo: 'ANUAL', descripcion: 'Declaración anual PM e ISR', urgente: true });
}

return [{ json: { obligations, fecha: today.toISOString(), hasObligations: obligations.length > 0 } }];
